--修改vip维护页面的sql-050319901

DELETE FROM G_INQ_CFG WHERE SQL_ID='050319901';

INSERT INTO "G_INQ_CFG"("CORP_ID", "SQL_ID", "SQL_STRING", "DETAIL_SQL_STRING", "SYSTEM", "REMARKS", "UPD_TIME", "CRT_TIME", "RSV1", "RSV2", "RSV3", "RSV4", "RSV5") VALUES ('SCB', '050319901', 'SELECT
    t.VIP_TYPE,
    t.VIP_ACTNO,
    t.VIP_NAME,
    t.VIP_LEVEL,
	t.REMARKS,
	t.CRT_TIME,
	t.UPD_TIME
FROM
    SCB_VIPACCT_INFO t
WHERE
    1=1
AND VIP_TYPE=:"VIP_TYPE"
AND upper(VIP_ACTNO)=upper(:"VIP_ACTNO")
AND VIP_NAME=:"VIP_NAME"
AND VIP_LEVEL=:"VIP_LEVEL"', NULL, 'SCB', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);


