--修改vip维护查询页面的sql-050229801

DELETE FROM G_INQ_CFG WHERE SQL_ID='050229801';

INSERT INTO "G_INQ_CFG"("CORP_ID", "SQL_ID", "SQL_STRING", "DETAIL_SQL_STRING", "SYSTEM", "REMARKS", "UPD_TIME", "CRT_TIME", "RSV1", "RSV2", "RSV3", "RSV4", "RSV5") VALUES ('SCB', '050229801', 'SELECT
    t.VIP_TYPE,
    t.VIP_ACTNO,
    t.VIP_NAME,
    t.VIP_LEVEL,
    t.REMARKS,
    case t.MOD_STATUS when ''00'' then ''正常'' else ''修改中'' end as MOD_STATUS,
    t.CRT_USER,
    t.CRT_TIME,
    t.UPD_USER,
    t.UPD_TIME,
    t.APV_USER,
    t.APV_TIME
FROM
    SCB_VIPACCT_INFO t
WHERE
    1=1
AND upper(t.VIP_ACTNO)=upper(:"VIP_ACTNO")
', NULL, 'SCB', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);-- 服务配置
