-- 页面查询SQL
delete from G_INQ_CFG where SQL_ID in ('050449901', '050449902', '050449903', '050449904');
INSERT INTO G_INQ_CFG (CORP_ID, SQL_ID, SQL_STRING, DETAIL_SQL_STRING, SYSTEM, REMARKS, UPD_TIME, CRT_TIME, RSV1, RSV2, RSV3, RSV4, RSV5) VALUES ('ALL', '050449901', 'select (select PARA_VALUE from G_PARAS where PARA_KEY = ''PMTS_DTT_INTERVAL'' )    as PMTS_DTT_INTERVAL,
       (select PARA_VALUE from G_PARAS where PARA_KEY = ''PMTS_DTT_FAIL_TIME'' )   as PMTS_DTT_FAIL_TIME,
       (select PARA_VALUE from G_PARAS where PARA_KEY = ''PMTS_ROUTE_STRATEGY'' )  as PMTS_ROUTE_STRATEGY,
       (select PARA_VALUE from G_PARAS where PARA_KEY = ''PMTS_DTT_LOG_RETENTION_DAYS'' ) as PMTS_DTT_LOG_RETENTION_DAYS
from dual', null, 'CIPS', null, null, null, null, null, null, null, null);
INSERT INTO G_INQ_CFG (CORP_ID, SQL_ID, SQL_STRING, DETAIL_SQL_STRING, SYSTEM, REMARKS, UPD_TIME, CRT_TIME, RSV1, RSV2, RSV3, RSV4, RSV5) VALUES ('ALL', '050449902', 'select * from cips_pmts_node order by APP_SERVER_NAME, PMTS_SERVER_NAME', null, 'CIPS', null, null, null, null, null, null, null, null);
INSERT INTO G_INQ_CFG (CORP_ID, SQL_ID, SQL_STRING, DETAIL_SQL_STRING, SYSTEM, REMARKS, UPD_TIME, CRT_TIME, RSV1, RSV2, RSV3, RSV4, RSV5) VALUES ('ALL', '050449903', 'select *
from CIPS_PMTS_DTT_LOG
where APP_SERVER_NAME = :"APP_SERVER_NAME"
  and PMTS_SERVER_NAME = :"PMTS_SERVER_NAME"
  and DTT_REQ_SND_TIME >= :"BEGIN_TIME"
  and DTT_REQ_SND_TIME <= :"END_TIME"
  order by DTT_REQ_SND_TIME desc', null, 'CIPS', null, null, null, null, null, null, null, null);
INSERT INTO G_INQ_CFG (CORP_ID, SQL_ID, SQL_STRING, DETAIL_SQL_STRING, SYSTEM, REMARKS, UPD_TIME, CRT_TIME, RSV1, RSV2, RSV3, RSV4, RSV5) VALUES ('ALL', '050449904', 'select *
from CIPS_PMTS_NODE_STATUS_CHG_LOG
where APP_SERVER_NAME = :"APP_SERVER_NAME"
  and PMTS_SERVER_NAME = :"PMTS_SERVER_NAME"
  and STATUS_CHG_TIME >= :"BEGIN_TIME"
  and STATUS_CHG_TIME <= :"END_TIME"
  order by STATUS_CHG_TIME desc', null, 'CIPS', null, null, null, null, null, null, null, null);


